//
// Generated by tools/png2sprite from a reference image (not committed).
// Command: go run ./tools/png2sprite -n <reference.png> -width 24 -colors 12 -bg-tolerance 30 -out go -name hotDog -style halfblock
var hotDogPalette = map[rune]string{
	'A': "95",  // muted mauve / shadow blend  — approx RGB(135,95,95)
	'B': "124", // medium red / sausage core   — approx RGB(175,0,0)
	'C': "131", // warm mauve / sausage edge   — approx RGB(175,95,95)
	'D': "166", // orange-red / sausage bright — approx RGB(215,95,0)
	'E': "173", // sandy orange / bun edge     — approx RGB(215,135,95)
	'F': "179", // golden / bun transition     — approx RGB(215,175,95)
	'G': "214", // gold-orange / bun body      — approx RGB(255,175,0)
	'H': "220", // bright yellow / mustard     — approx RGB(255,215,0)
	'I': "221", // pale yellow / bun highlight — approx RGB(255,215,95)
	'J': "236", // dark charcoal / outline     — approx RGB(48,48,48)
	'K': "238", // mid charcoal / soft outline — approx RGB(68,68,68)
}

